class Solution {
public:
    int compareVersion(string version1, string version2) {
        int n1 = getRevisionValue(version1);
        int n2 = getRevisionValue(version2);
        return (n1 < n2) ? -1 : ((n1 == n2) ? 0 : 1);
    }

    int getRevisionValue(string version) {
        int result = 0;
        for (char c : version) {
            if (c == '.') {
                continue;
            }
            result = result * 10 + c - '0';
        }
        return result;
    }
};
